// isValidJSIdentifier checks if a string is a valid JavaScript identifier
func isValidJSIdentifier(s string) bool {
	// Check if it matches the pattern of a valid JS identifier
	matched, _ := regexp.MatchString(`^[a-zA-Z_$][a-zA-Z0-9_$]*$`, s)
	return matched
}

// validateConditionScript performs basic validation on the script to prevent obvious injection attempts
func validateConditionScript(script string) error {
	// Remove whitespace to check for obvious malicious patterns
	cleaned := strings.ReplaceAll(script, " ", "")

	// Check for obvious attempts to break out of expression context
	invalidPatterns := []string{
		"function", "var ", "let ", "const ", "if(", "if", "while", "for(", "eval", "delete",
		"this.", "global", "window", "document", // Browser-specific objects that shouldn't be accessible
		"__proto__", "constructor", "prototype", // Dangerous prototype access
	}

	scriptLower := strings.ToLower(cleaned)
	for _, pattern := range invalidPatterns {
		if strings.Contains(scriptLower, strings.ToLower(strings.ReplaceAll(pattern, " ", ""))) {
			return fmt.Errorf("invalid pattern detected in script: %s", pattern)
		}
	}

	// Prevent access to potentially dangerous properties
	dangerousAccessPattern := regexp.MustCompile(`\.(constructor|prototype|__proto__|hasOwnProperty|propertyIsEnumerable|isPrototypeOf|valueOf|toLocaleString|toString)\b`)
	if dangerousAccessPattern.MatchString(script) {
		return errors.New("access to dangerous object properties is not allowed")
	}

	return nil
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Validate the input script for potential security issues
	if err := validateConditionScript(conditionScript); err != nil {
		return nil, fmt.Errorf("script validation failed: %w", err)
	}

	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()

		// Sanitize keys in the item to ensure they're valid JS identifiers
		safeItem := make(map[string]interface{})
		for k, v := range item {
			if !isValidJSIdentifier(k) {
				return nil, fmt.Errorf("invalid key in item: %s", k)
			}
			safeItem[k] = v
		}

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", safeItem)
		if err != nil {
			return nil, fmt.Errorf("failed to set item in VM: %w", err)
		}

		// Run the condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("script execution failed: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item) // Add original item to preserve original structure
		}
	}

	return result, nil
