func isValidJavaScript(script string) error {
	unsafePatterns := []*regexp.Regexp{
		// Check for access to global objects like Object, Function, etc.
		regexp.MustCompile(`(?i)\b(Object|Function|Array|String|Number|Boolean|Date|RegExp|Error|EvalError|RangeError|ReferenceError|SyntaxError|TypeError|URIError|global|process|require|import|arguments|eval|constructor|__proto__|prototype)\s*\.\s*\w+`),
