		// Check for new Function calls
		regexp.MustCompile(`(?i)\bnew\s+Function\s*\(`),
		// Check for accessing constructor properties
		regexp.MustCompile(`(?i)\.(constructor|__proto__|prototype)`),
	}

	script = strings.TrimSpace(script)

	for _, pattern := range unsafePatterns {
		if pattern.MatchString(script) {
			return errors.New("script contains potentially unsafe operations")
		}
	}

	return nil
}

