		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Run the condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// validateScript performs basic validation to prevent potentially dangerous JavaScript operations
func validateScript(script string) error {
	// Check for potentially dangerous patterns like function constructors, eval, etc.
	dangerousPatterns := []string{
		`\beval\s*\(`,
		`\bFunction\s*\(`,
		`\bsetTimeout\s*\(`,
		`\bsetInterval\s*\(`,
		`\bimport\s+`,
		`\brequire\s*\(`,
		`\bprocess\b`,
		`\bglobal\b`,
		`\bwindow\b`,
		`\bdocument\b`,
		`\bthis\b`,
	}

	for _, pattern := range dangerousPatterns {
		matched, err := regexp.MatchString(pattern, script)
		if err != nil {
			continue // If regex fails to compile, continue checking other patterns
		}
		if matched {
			return errors.New("script contains potentially dangerous operation: " + pattern)
		}
	}

	return nil
}

