package main

import (
	"errors"
	"fmt"
	"regexp"
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Validate the script for potentially dangerous patterns
	if err := validateScript(conditionScript); err != nil {
		return nil, err
	}

	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()

		// Set a reasonable execution timeout to prevent infinite loops
		done := make(chan bool, 1)
		go func() {
			select {
			case <-time.After(100 * time.Millisecond): // 100ms timeout per item evaluation
				vm.Interrupt <- func() {
					panic("Execution timeout")
				}
			case <-done:
				// Evaluation completed successfully
			}
		}()

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			close(done)
			return nil, fmt.Errorf("failed to set item in VM: %w", err)
		}

		// Run the condition script
		value, err := vm.Run(conditionScript)
		close(done) // Allow the timeout goroutine to exit

		if err != nil {
			// Check if it's a timeout error
			if isTimeoutError(err) {
				return nil, errors.New("script execution timed out")
			}
			return nil, fmt.Errorf("script execution failed: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// validateScript checks the script for potentially dangerous patterns
func validateScript(script string) error {
	dangerousPatterns := []*regexp.Regexp{
		// Prevent access to built-in objects that might allow harmful operations
		regexp.MustCompile(`(?i)\b(import|require|eval|function constructor)\b`),
		// Prevent accessing external resources
		regexp.MustCompile(`(?i)\b(xmlhttprequest|fetch|navigator|window|document|global)\b`),
		// Prevent file system access (if available through some means)
		regexp.MustCompile(`(?i)\b(fs|fileSystem|readFile|writeFile|exec|spawn)\b`),
		// Prevent direct prototype manipulation
		regexp.MustCompile(`\bprototype\b.*(?:__defineGetter__|__defineSetter__|__lookupGetter__|__lookupSetter__)`),
	}

	for _, pattern := range dangerousPatterns {
		if pattern.MatchString(script) {
			return fmt.Errorf("forbidden pattern detected in script: %s", pattern.String())
		}
	}

	return nil
}

// isTimeoutError checks if the error is caused by our execution timeout
func isTimeoutError(err error) bool {
	return err != nil && err.Error() == "Script execution interrupted"
}

