	if strings.Contains(conditionScript, "delete") || strings.Contains(conditionScript, "eval") ||
		strings.Contains(conditionScript, "Function") || strings.Contains(conditionScript, "setTimeout") ||
		strings.Contains(conditionScript, "setInterval") || strings.Contains(conditionScript, "import") ||
		strings.Contains(conditionScript, "require") {
		return nil, errors.New("invalid script: contains forbidden keywords")
	}

	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()

		// Set a timeout to prevent infinite loops or heavy computation
		done := make(chan bool, 1)
		go func() {
			select {
			case <-done:
				return
			}
		}()

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Run the condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			// Check if the error is related to execution timeout or other runtime issues
			return nil, fmt.Errorf("script execution error: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}

		done <- true
	}

	return result, nil
}

